import { BankAccount } from '@domain/bankAccount';
import { ApiClient } from '@service/anedot/client';
import { PaginatedResponse, PaginationParams } from '@service/anedot/interfaces';
import { useGetAccount } from '@state/accounts';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils';
import { TaskQueue } from '@utils/taskQueue';
import { createContext, useContext } from 'react';
import { useQuery } from 'react-query';

type Params = PaginationParams & { queue?: TaskQueue<PaginatedResponse<BankAccount[]>> };

const _useGetAllBankAccounts = (params?: Params) => {
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;
  const searchParams = makeSearchParams({
    account_id: accountId,
    page: params?.page ?? 1,
    per_page: params?.perPage ?? 100,
  });

  const { data, isLoading } = useQuery<PaginatedResponse<BankAccount[]>, string>(
    generateQueryKey({
      accountId,
      parameters: searchParams.raw,
      resourceKey: resourceKeys.bankAccounts,
    }),
    () => {
      const task = () =>
        new ApiClient().get<PaginatedResponse<BankAccount[]>>(`/bank_accounts?${searchParams}`);

      return params?.queue ? params.queue.enqueue(task) : task();
    },
    {
      enabled: !!accountId,
    }
  );

  return {
    bankAccounts: data?.data,
    isLoadingBankAccounts: isLoading,
    meta: data?.meta,
  };
};

export const UseGetAllBankAccountsContext = createContext(_useGetAllBankAccounts);
export const useGetAllBankAccounts = (params?: Params) =>
  useContext(UseGetAllBankAccountsContext)(params);

