const createField = (
  label: string,
  value?: ReactNode,
  options?: { isPresent?: boolean; isRequired?: boolean }
): SummaryField => {
  const shouldMarkMissing =
    options?.isRequired && !(options?.isPresent ?? hasRenderableValue(value));

  return {
    isMissing: shouldMarkMissing,
    label,
    value,
  };
};

const isOrganizationApplicationStep = (
  value: string | null | undefined
): value is OrganizationApplicationStep => {
  if (!value) {
    return false;
