import { IAccountShow } from '@domain/account';
import { ApiClient } from '@service/anedot/client';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { useQuery } from 'react-query';

type UseGetOneAccountsProps = {
  accountId?: string;
  refetchInterval?: number;
};

export const getAccount = async (accountId?: string) => {
  return new ApiClient().get<IAccountShow>(`/accounts/${accountId}`);
