import { useRollbar } from '@rollbar/react';
import { useAuthStore } from '@state/authStore';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { isDevelopment, makeSearchParams } from '@utils';
import { getApiHostname } from '@utils/getApiHostname';
import { useGetAccountId } from '@utils/useGetAccountId';
import { useCallback, useMemo } from 'react';
import { useQuery } from 'react-query';
import Rollbar from 'rollbar';
import { FeatureToggle, FeatureVariant } from '../types';

const APP_NAME = 'anedot-frontend';
const DEV_INSTANCE = 'https://toggles.anedot.me/api/features/proxy';
const FIFTEEN_MINUTES = 15 * 60 * 1000;
const TWO_MINUTES = 2 * 60 * 1000;

type Response = {
  getVariant: (name: string) => FeatureVariant | undefined;
  isEnabled: (name: string) => boolean;
  isError: boolean;
  isFetched: boolean;
  isLoading: boolean;
  toggles?: FeatureToggle[];
};

type Params = {
  accountId?: string | null;
  rollbar?: Rollbar;
};

export const useFeatureFlagsWithOptionalLogging = ({
  accountId: providedAccountId,
  rollbar,
}: Params = {}): Response => {
  const currentAccountId = useGetAccountId();
  const { user } = useAuthStore();

  const accountId = useMemo(
    () => providedAccountId || currentAccountId,
    [currentAccountId, providedAccountId]
  );

  const params = makeSearchParams({
    accountId,
    appName: APP_NAME,
    userId: user?.id,
  });

  const query = useQuery<FeatureToggle[], string>(
    generateQueryKey({
      accountId,
      parameters: params.raw,
      resourceKey: resourceKeys.featureFlags,
    }),
    async () => {
      return fetch(
        `${
          isDevelopment() ? DEV_INSTANCE : `${getApiHostname()}/api/features/proxy`
        }?${params.toString()}`
      )
        .then((response) => {
          if (response.ok && response.headers?.get('Content-Type')?.includes('application/json')) {
            return response.json();
          }

          return response.text();
        })
        .then((data) => {
          if (typeof data === 'object') {
            return data.toggles || [];
          }

          rollbar?.error(data);
          return [];
        })
        .catch((error) => rollbar?.error(error));
    },
    {
      keepPreviousData: true,
      refetchInterval: FIFTEEN_MINUTES,
      staleTime: TWO_MINUTES,
    }
  );

  const isEnabled = useCallback(
    (name: string) => {
      return !!query.data?.find?.((toggle) => toggle?.name === name && toggle?.enabled);
    },
    [query.data]
  );

  const getVariant = useCallback(
    (name: string) => {
      return query.data?.find?.((toggle) => toggle?.name === name && toggle?.enabled)?.variant;
    },
    [query.data]
  );

  return {
    getVariant,
    isEnabled,
    isError: query.isError,
    isFetched: query.isFetched,
    isLoading: query.isLoading,
    toggles: query.data as FeatureToggle[],
  };
};

export const useFeatureFlags = ({ accountId }: Partial<Params> = {}) => {
  const rollbar = useRollbar();

  return useFeatureFlagsWithOptionalLogging({ accountId, rollbar });
};

