import { AccountStatus } from '@domain/accountStatus';
import { useGetAccount } from '@state/accounts';
import { Navigate, NavigateProps } from 'react-router-dom';

type Props = WithChildren & {
  redirect: NavigateProps['to'];
  replace?: NavigateProps['replace'];
  statuses?: AccountStatus[];
};

export const AccountStatusGuard = ({ children, redirect, replace, statuses }: Props) => {
  const { currentAccount } = useGetAccount();

  if (!currentAccount) {
    return null;
  } else if (currentAccount.status && statuses?.includes(currentAccount.status)) {
    return children;
  }

  return <Navigate replace={replace} to={redirect} />;
};

