];

export const App = () => {
  const routeConfig = useRouteConfig();
  const routes = useRoutes(routeConfig as RouteObject[]);

  const { pathname } = useLocation();

  const isPublicAP = useMemo(
    /*
      Check if current pathname is either a public action page or confirmation page.
