import { IUserMeResponse, PermissionList } from '@domain/user';
import { useGetMe } from '@state/user/me';
import { isUserAdmin } from '@utils/isAdmin';
import { isUserOwner } from '@utils/isOwner';
import { isUserSuperadmin } from '@utils/isSuperadmin';
import { TaskQueue } from '@utils/taskQueue';
import { useGetAccountId } from '@utils/useGetAccountId';
import { useCallback, useMemo } from 'react';
import { getFilledPermissionToggles } from '../getFilledPermissionToggles';

type Params = {
  accountId?: string;
  queue?: TaskQueue<IUserMeResponse>;
};

export const usePermissions = ({ accountId: accountIdOverride, queue }: Params = {}) => {
  // Favor using the query params over useGetAccount so that you do not pay the
  // price of waiting for the account to load to extract the permissions
  // associated with the account
  const currentAccountId = useGetAccountId();
  const accountId = accountIdOverride || currentAccountId;

  const { user } = useGetMe({
    accountId,
    enabled: !!accountId,
    queue,
  });

  const { canManageGrossDeposits = false, permissionLists } = user ?? {};
  const owner = isUserOwner(user, accountId);
  const superadmin = isUserSuperadmin(user, accountId);
  const admin = isUserAdmin(user, accountId);

  // Permissions are per account, but the staff status should be account independent
  const { user: { staffRole } = {} } = useGetMe({});

  const adjustedPermissions = useMemo(() => {
    if (!user) {
      return getFilledPermissionToggles({ withValue: false });
    }

    if (owner || superadmin || staffRole) {
      return getFilledPermissionToggles({ withValue: true });
    }

    return (
      permissionLists?.find((list) => list.accountId === accountId)?.accessAttributes ??
      getFilledPermissionToggles({ withValue: false })
    );
  }, [user, owner, superadmin, staffRole, permissionLists, accountId]);

  const canSetupAccount = useMemo(
    () =>
      adjustedPermissions?.accountsWrite &&
      adjustedPermissions?.actionPagesRead &&
      adjustedPermissions?.actionPagesWrite &&
      adjustedPermissions?.actionPagesExport,
    [
      adjustedPermissions?.accountsWrite,
      adjustedPermissions?.actionPagesExport,
      adjustedPermissions?.actionPagesRead,
      adjustedPermissions?.actionPagesWrite,
    ]
  );

  const canAssignPermissionList = useCallback(
    (permissionList?: PermissionList) =>
      staffRole ||
      (permissionList
        ? Object.keys(permissionList.accessAttributes).every(
            (key) =>
              // I'm sure theres a better way to type the string such that it is limited
              // to the key set of permission toggles but such is life when you try to
              // force typing on an untyped language
              // @ts-ignore
              adjustedPermissions[key] ||
              // @ts-ignore
              adjustedPermissions[key] === permissionList.accessAttributes[key]
          )
        : false),
    [adjustedPermissions, staffRole]
  );

  return {
    ...adjustedPermissions,
    accountId,
    admin,
    canAssignPermissionList,
    canManageGrossDeposits,
    canSetupAccount,
    isLoadingPermissions: !user,
    owner,
    staffRole,
    superadmin,
  };
};

