export const useGetAccountConfiguration = (
  accountId?: string
): {
  accountConfiguration?: AccountConfiguration;
  isLoading: boolean;
} => {
  const { currentAccount } = useGetAccount();
  const normalizedAccountId = accountId || currentAccount?.id;
  const params = makeSearchParams({
    accountId: normalizedAccountId,
  });

  const query = useQuery<AccountConfiguration, IErrorResponse>(
    generateQueryKey({
      accountId: normalizedAccountId,
      resourceKey: resourceKeys.accountConfiguration,
    }),
    async () => {
