type NavAccountPickerProps = Pick<NavProps, 'variant'>;

export const NavAccountPicker = ({ variant }: NavAccountPickerProps): JSX.Element => {
  const { t } = useTranslation('navRoutes');

  const { user } = useAuthStore();

  const navigate = useNavigate();
  const filter = useCallback((route: RouteOption) => !route.isAccountScoped, []);
  const routeConfig = useRouteConfig(filter);
  const location = useLocation();
  const match = useMemo(
    // casting routeConfig, RouteOption extends RouteObject
    // but matchRoutes doesn't know about it
    () => matchRoutes(routeConfig as RouteObject[], location),
    [location, routeConfig]
  );
  const { currentAccount } = useGetAccount();
  const [searchTerm, setSearchTerm] = useState<string>('');
  const {
    data: accounts,
    fetchNextPage: fetchMoreAccounts,
    hasNextPage: hasMoreAccounts,
    isLoading,
  } = useGetInfiniteAccounts({
    q: searchTerm,
  });

  const bypassApplicationStatus = useFeatureFlag('access.bypassApplicationStatus');

  const onSelectAccount = useCallback(
    ({ id, status }: Account) => {
      const { path, useAssign } = getAccountNavigationPath({
        bypassApplicationStatus,
        id,
        isStaffUser: !!user?.staffRole,
        match,
        status,
      });

      if (useAssign) {
        window.location.assign(path);
      } else {
        navigate(path);
      }
    },
    [bypassApplicationStatus, match, navigate, user?.staffRole]
  );

  return (
    <Menu onClose={() => setSearchTerm('')}>
      {({ isOpen }) => (
        <>
          <MenuButton
            as={Button}
            isLoading={isLoading}
            rightIcon={<ToggleChevron isOpen={isOpen} />}
            textAlign="left"
            // @ts-ignore
            variant={`secondary${toTitleCase(variant)}`}
            width={{ base: '100%', xl: 'auto' }}
          >
            {currentAccount ? currentAccount.displayName : t('accountPicker.select')}
          </MenuButton>
          <MenuList width="280px" zIndex={5}>
            <FilterMenuItem isOpen={isOpen} searchTerm={searchTerm} setSearchTerm={setSearchTerm} />
            <Box maxHeight="331px">
              <InfiniteScroll
                dataLength={(accounts || []).length}
                hasMore={!!hasMoreAccounts}
                height={331}
                loader={<Loading />}
                next={fetchMoreAccounts}
              >
                {accounts?.map((account, idx) => {
                  if (
                    (account.status === 'paused' && accounts[idx - 1]?.status !== 'paused') ||
                    (account.status === 'disabled' &&
                      accounts[idx - 1]?.status !== 'disabled' &&
                      accounts[idx - 1]?.status !== 'paused')
                  ) {
                    return (
                      <Fragment key={account.id}>
                        <MenuDivider />
                        <Box padding={4} paddingBottom={0}>
                          <Label variant="bold">{t('accountPicker.pausedDisabled')}</Label>
                        </Box>
                        <AccountItem account={account} onSelect={onSelectAccount} />
                      </Fragment>
                    );
                  }

                  return (
                    <AccountItem account={account} key={account.id} onSelect={onSelectAccount} />
                  );
                })}
              </InfiniteScroll>
            </Box>
            <ApplyMenuItem />
          </MenuList>
        </>
      )}
    </Menu>
  );
};

