import { ApiClient, ApiClientError, ApiNamespace } from '@service/anedot/client';
import {
  InfiniteQueryResponse,
  PaginatedResponse,
  PaginationParams,
} from '@service/anedot/interfaces';
import { GeneratedQueryKey, generateQueryKey } from '@state/cacheHelper/keyFactory';
import { UseInfiniteQueryOptions, useInfiniteQuery } from 'react-query';
import { makeSearchParams } from '../params';
import { Params } from '../params/cleanParams';

export type UseGetInfiniteOptions<TQueryFnData = any> = {
  namespace: ApiNamespace;
  performRedirect: boolean;
  resourceKey?: string;
} & Omit<
  UseInfiniteQueryOptions<
    TQueryFnData,
    ApiClientError,
    TQueryFnData,
    TQueryFnData,
    GeneratedQueryKey
  >,
  'queryFn' | 'queryKey'
>;

export type UseGetInfiniteParams = Partial<Pick<PaginationParams, 'perPage'>> & Params;

export type UseGetInfinitePaginatedResponse = {
  nextPageCursor?: number;
};

const defaultUseGetOptions: UseGetInfiniteOptions = {
  namespace: 'org',
  performRedirect: true,
};

export const useGetInfinite = <DataShape, P extends UseGetInfiniteParams = UseGetInfiniteParams>(
  path: string,
  params: P,
  options: Partial<UseGetInfiniteOptions<PaginatedResponse<DataShape[]>>> = {}
) => {
  const normalizedOptions: UseGetInfiniteOptions<PaginatedResponse<DataShape[]>> = {
    ...defaultUseGetOptions,
    ...options,
  };

  const { namespace, performRedirect, resourceKey, ...useInfiniteQueryOptions } = normalizedOptions;

  const normalizedResourceKey = resourceKey || `/${namespace}/v3${path}`;

  const queryParams = makeSearchParams(params);

  const queryKey = generateQueryKey({
    parameters: queryParams.raw,
    resourceKey: normalizedResourceKey,
  });

  const query = useInfiniteQuery<
    InfiniteQueryResponse<DataShape[]>,
    ApiClientError,
    PaginatedResponse<DataShape[]>,
    GeneratedQueryKey
  >(
    queryKey,
    async ({ pageParam = 1 }) => {
      queryParams.set('page', pageParam);
      const hydratedPath = `${path}?${queryParams.toString()}`;
      const resp = await new ApiClient({ namespace, performRedirect }).get<
        PaginatedResponse<DataShape[]>
      >(hydratedPath);

      return {
        ...resp,
        nextPageCursor: pageParam < resp.meta.totalPages ? pageParam + 1 : undefined,
      };
    },
    {
      keepPreviousData: true,
      ...useInfiniteQueryOptions,
      getNextPageParam: (lastPage) => lastPage.nextPageCursor,
    }
  );

  return {
    ...query,
    data: query.data?.pages.flatMap((page) => page.data),
    totalCount: query.data?.pages[0].meta.totalCount,
  };
};

